import os
import io
import csv
import numpy as np
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import pandas as pd
from PIL import Image
import json
from datetime import datetime

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_FOLDER = 'models'
DATA_FOLDER = 'training_data'
ALLOWED_EXTENSIONS = {'csv', 'png', 'jpg', 'jpeg'}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_FOLDER, exist_ok=True)
os.makedirs(DATA_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 50 * 1024 * 1024

class ImageClassificationModel:
    def __init__(self, num_classes=10, img_height=224, img_width=224):
        self.num_classes = num_classes
        self.img_height = img_height
        self.img_width = img_width
        self.model = None
        self.training_data = []
        self.training_labels = []
        
    def build_model(self):
        self.model = keras.Sequential([
            layers.Rescaling(1./255, input_shape=(self.img_height, self.img_width, 3)),
            layers.Conv2D(32, 3, activation='relu'),
            layers.MaxPooling2D(),
            layers.Conv2D(64, 3, activation='relu'),
            layers.MaxPooling2D(),
            layers.Conv2D(128, 3, activation='relu'),
            layers.MaxPooling2D(),
            layers.Flatten(),
            layers.Dense(128, activation='relu'),
            layers.Dropout(0.5),
            layers.Dense(self.num_classes, activation='softmax')
        ])
        
        self.model.compile(
            optimizer='adam',
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )
        
    def train(self, epochs=10, batch_size=32):
        if len(self.training_data) == 0:
            return None
            
        X = np.array(self.training_data)
        y = np.array(self.training_labels)
        
        history = self.model.fit(
            X, y,
            epochs=epochs,
            batch_size=batch_size,
            validation_split=0.2
        )
        
        return history
    
    def add_training_example(self, image_array, label):
        self.training_data.append(image_array)
        self.training_labels.append(label)
    
    def save_model(self, path):
        self.model.save(path)
    
    def load_model(self, path):
        self.model = keras.models.load_model(path)

model_instance = ImageClassificationModel()
model_instance.build_model()

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def process_image(file_path, target_size=(224, 224)):
    img = Image.open(file_path)
    img = img.convert('RGB')
    img = img.resize(target_size)
    img_array = np.array(img)
    return img_array

@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)
        
        try:
            df = pd.read_csv(filepath)
            
            if 'image_path' not in df.columns or 'label' not in df.columns:
                return jsonify({'error': 'CSV must contain image_path and label columns'}), 400
            
            added_count = 0
            for _, row in df.iterrows():
                img_path = row['image_path']
                label = int(row['label'])
                
                if os.path.exists(img_path):
                    img_array = process_image(img_path)
                    model_instance.add_training_example(img_array, label)
                    added_count += 1
            
            return jsonify({
                'message': 'CSV processed successfully',
                'examples_added': added_count,
                'total_examples': len(model_instance.training_data)
            }), 200
            
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/upload_image', methods=['POST'])
def upload_image():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    if 'label' not in request.form:
        return jsonify({'error': 'No label provided'}), 400
    
    file = request.files['file']
    label = int(request.form['label'])
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        filename = f"{timestamp}_{filename}"
        filepath = os.path.join(DATA_FOLDER, filename)
        file.save(filepath)
        
        try:
            img_array = process_image(filepath)
            model_instance.add_training_example(img_array, label)
            
            return jsonify({
                'message': 'Image uploaded and added to training set',
                'filename': filename,
                'label': label,
                'total_examples': len(model_instance.training_data)
            }), 200
            
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/train', methods=['POST'])
def train_model():
    data = request.get_json() or {}
    epochs = data.get('epochs', 10)
    batch_size = data.get('batch_size', 32)
    
    if len(model_instance.training_data) == 0:
        return jsonify({'error': 'No training data available'}), 400
    
    try:
        history = model_instance.train(epochs=epochs, batch_size=batch_size)
        
        model_path = os.path.join(MODEL_FOLDER, f'model_{datetime.now().strftime("%Y%m%d_%H%M%S")}.h5')
        model_instance.save_model(model_path)
        
        return jsonify({
            'message': 'Model trained successfully',
            'model_path': model_path,
            'final_accuracy': float(history.history['accuracy'][-1]),
            'final_val_accuracy': float(history.history['val_accuracy'][-1]),
            'training_examples': len(model_instance.training_data)
        }), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        try:
            img_array = process_image(io.BytesIO(file.read()))
            img_array = np.expand_dims(img_array, axis=0)
            
            predictions = model_instance.model.predict(img_array)
            predicted_class = int(np.argmax(predictions[0]))
            confidence = float(np.max(predictions[0]))
            
            return jsonify({
                'predicted_class': predicted_class,
                'confidence': confidence,
                'all_predictions': predictions[0].tolist()
            }), 200
            
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/contribute', methods=['POST'])
def contribute_example():
    if 'file' not in request.files or 'label' not in request.form:
        return jsonify({'error': 'File and label required'}), 400
    
    file = request.files['file']
    label = int(request.form['label'])
    contributor = request.form.get('contributor', 'anonymous')
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        filename = f"{contributor}_{timestamp}_{filename}"
        filepath = os.path.join(DATA_FOLDER, filename)
        file.save(filepath)
        
        try:
            img_array = process_image(filepath)
            model_instance.add_training_example(img_array, label)
            
            metadata = {
                'filename': filename,
                'label': label,
                'contributor': contributor,
                'timestamp': timestamp
            }
            
            metadata_path = os.path.join(DATA_FOLDER, 'contributions.json')
            contributions = []
            if os.path.exists(metadata_path):
                with open(metadata_path, 'r') as f:
                    contributions = json.load(f)
            
            contributions.append(metadata)
            
            with open(metadata_path, 'w') as f:
                json.dump(contributions, f, indent=2)
            
            return jsonify({
                'message': 'Contribution accepted',
                'filename': filename,
                'total_contributions': len(contributions),
                'total_training_examples': len(model_instance.training_data)
            }), 200
            
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/stats', methods=['GET'])
def get_stats():
    contributions_path = os.path.join(DATA_FOLDER, 'contributions.json')
    total_contributions = 0
    
    if os.path.exists(contributions_path):
        with open(contributions_path, 'r') as f:
            contributions = json.load(f)
            total_contributions = len(contributions)
    
    return jsonify({
        'total_training_examples': len(model_instance.training_data),
        'total_contributions': total_contributions,
        'num_classes': model_instance.num_classes,
        'model_built': model_instance.model is not None
    }), 200

@app.route('/load_model', methods=['POST'])
def load_model():
    data = request.get_json()
    model_path = data.get('model_path')
    
    if not model_path or not os.path.exists(model_path):
        return jsonify({'error': 'Invalid model path'}), 400
    
    try:
        model_instance.load_model(model_path)
        return jsonify({'message': 'Model loaded successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)